// Validity check for §2: are the bench's keys "cheating"? In bench/hotpot.ts I derived keys
// myself (title + mentioned-titles), which mirrors the gold bridge structure. Here the keys
// were instead generated by INDEPENDENT subagents that saw ONLY each paragraph's text (no
// question, no gold supports, no other paragraphs' role) and tagged it for findability — i.e.
// realistic keymem write-time keying. If the GRAPH gain on bridge questions survives with these
// blind agent keys, the "you keyed it to match the answer" objection dies.
//
//   tsx bench/hotpot-agentkeys.ts <agent-keys.json>
import { mkdtemp, rm, readFile, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join, resolve } from "node:path";
import MiniSearch from "minisearch";

process.env.EMBEDDING_BACKEND ??= "local";
process.env.LOCAL_EMBEDDING_MODEL ??= "bge-m3";

type Row = { question: string; type: string; support: string[]; titles: string[]; paras: string[] };
const all = JSON.parse(await readFile(resolve("bench/hotpot-slice.json"), "utf-8")) as Row[];
const bridge = all.filter((r) => r.type === "bridge").slice(0, 40);
const keysPath = process.argv[2];
const agentKeys = JSON.parse(await readFile(keysPath, "utf-8")) as Record<string, string[]>;

const { LOCAL_EMBEDDING_MODEL } = await import("../src/embedding.ts");

const TOPK = 5;
const CONDITIONS = ["BM25", "DIRECT", "GRAPH"];
type Agg = { n: number; recall: number; both: number };
const mk = (): Agg => ({ n: 0, recall: 0, both: 0 });
const out: Record<string, Agg> = {}; for (const c of CONDITIONS) out[c] = mk();
let keyedCount = 0, fallbackCount = 0;

const dir = await mkdtemp(join(tmpdir(), "km-hpak-"));
let qi = 0;
for (const r of bridge) {
  process.env.KEYMEM_DATA_DIR = await mkdtemp(join(dir, "q-"));
  const mg = await import(`../src/memoryGraph.ts?ak=${qi}`);
  const g = new mg.MemoryGraph();
  await g.load();
  const gidToTitle: Record<string, string> = {};
  for (let pi = 0; pi < r.titles.length; pi++) {
    const id = `q${qi}p${pi}`;
    let keys = agentKeys[id];
    if (keys && keys.length) keyedCount++; else { keys = [r.titles[pi]]; fallbackCount++; }
    const [gid] = await g.add(r.paras[pi] ?? "", keys, {});
    gidToTitle[gid] = r.titles[pi];
  }
  const bm25 = new MiniSearch({ fields: ["content"], storeFields: ["id"], idField: "id" });
  bm25.addAll(r.titles.map((t, i) => ({ id: t, content: r.paras[i] ?? "" })));

  for (const cond of CONDITIONS) {
    let titles: string[];
    if (cond === "BM25") titles = (bm25.search(r.question, { fuzzy: 0.2, prefix: true }) as Array<{ id: string }>).map((x) => x.id);
    else { const res = await g.recall(r.question, TOPK, null, cond === "GRAPH", cond === "GRAPH" ? 2 : 1, 0, 0); titles = res.map((x: { id: string }) => gidToTitle[x.id]).filter(Boolean); }
    const top = titles.slice(0, TOPK);
    const found = r.support.filter((s) => top.includes(s)).length;
    const a = out[cond]; a.n++; a.recall += found / r.support.length; a.both += found === r.support.length ? 1 : 0;
  }
  qi++;
}
await rm(dir, { recursive: true, force: true });

const pct = (x: number) => `${(x * 100).toFixed(0)}%`;
console.log(`\nkeymem × HotpotQA bridge — BLIND AGENT KEYS — model=${LOCAL_EMBEDDING_MODEL}, N=${qi}`);
console.log(`(keys generated by subagents that saw only paragraph text — no question, no gold)`);
console.log(`paras keyed by agent: ${keyedCount}, fell back to title: ${fallbackCount}`);
console.log("─".repeat(58));
console.log(`metric              BM25    DIRECT    GRAPH`);
console.log(`support-recall@${TOPK}   ${CONDITIONS.map((c) => pct(out[c].recall / out[c].n).padStart(6)).join("  ")}`);
console.log(`both@${TOPK}            ${CONDITIONS.map((c) => pct(out[c].both / out[c].n).padStart(6)).join("  ")}`);
console.log("─".repeat(58));
await writeFile(resolve("bench/hotpot-agentkeys-results.json"), JSON.stringify({ model: LOCAL_EMBEDDING_MODEL, N: qi, keyedCount, fallbackCount, aggregates: out }, null, 2));
console.log("results → bench/hotpot-agentkeys-results.json");
